  ('pukao-8ec6300d-moex-00126', 'pukao-8ec6300d', 'pukao-8ec6300d-moex-112-156cbda0', 'sub-pukao-8ec6300d-01', NULL, 'single_choice', '下列由 C 語言程式撰寫的函數sort實作了何種排序法？ voidsort(inta[],intl,inth){ if(l>=h)return; intj,i,key; i=l;j=h;key=a[i]; while(i<j){ while(i<j&&a[j]>key)j--; if(i<j)a[i++]=a[j]; while(i<j&&a[i]<key)i++; if(i<j)a[j--]=a[i]; } a[i]=key; if(l<i-1) sort(a,l,i-1); if(i+1<h) sort(a,i+1,h); }', '["快速排序（Quicksort）", "插入排序（Insertionsort）", "選擇排序（Selectionsort）", "合併排序（Mergesort）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:42+00:00", "source_pdf_sha1": "0fd95dde2996", "answer_pdf_sha1": "12eeef66876e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "445", "s": "2804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電信工程"}'::jsonb, NULL),
